:root {
	/* Fonts */
	--font-family: 'Inter', 'Helvetica Neue', Helvetica, Arial, sans-serif;
	--font-weight-normal: 400;
	--font-weight-bold: 600;
	--font-size-body: 12px;
	--font-size-label: 14px;
	--font-size-test-notice: 12px;
	--font-size-input: 14px;
	--font-size-header: 22px; 
	--font-size-paragraph: 14px;
	--font-size-link: 12px;
	--font-size-error: 12px;
	--font-size-html-h1: 28px;
	--font-size-html-h2: 20px;
	--font-size-html-h3: 16px;
	--font-size-html-h4: 14px;
	--font-size-html-h5: 12px;
	--font-size-html-h6: 10px;
	--font-size-subheader: 14px;

	/* Colors - Adjusted for seamless immersion */
	--color-background: #ffffff; /* Pure white page background */
	--color-test-notice-text: #000000;
	--color-test-notice-bg: #f0f0f0;
	--color-test-notice-border: transparent;
	--color-card-bg: transparent; /* Removes the white box background */
	--color-card-border: transparent; /* Removes the box outline */
	--color-card-shadow: transparent; /* Removes the box shadow color */
	--color-link: #000000;
	--color-header: #000000;
	--color-label: #111111; 
	--color-input-border: #cccccc;
	--color-input-text: #000000;
	--color-focus-border: #000000; 
	--color-submit-btn-bg: #000000;
	--color-submit-btn-text: #ffffff;
	--color-error: #000000; 
	--color-required: #000000;
	--color-clear-button-bg: #aaaaaa;
	--color-html-text: #333333;
	--color-html-link: #000000;
	--color-header-subtext: #666666;

	/* Border Radii */
	--border-radius-card: 0px;
	--border-radius-input: 0px; 
	--border-radius-clear-btn: 50%;
	--card-border-radius: 0px;

	/* Spacing - Card padding removed so it doesn't act like an invisible box */
	--padding-container-top: 40px;
	--padding-card: 0px; /* Stripped to remove the invisible box constraints */
	--padding-test-notice-vertical: 12px;
	--padding-test-notice-horizontal: 24px;
	--margin-bottom-card: 24px;
	--padding-form-input: 14px;
	--card-padding: 0px; /* Stripped */
	--card-margin-bottom: 24px;

	/* Dimensions */
	--container-width: 480px; 
	--submit-btn-height: 48px;
	--checkbox-size: 16px;

	/* Others */
	--box-shadow-card: none; /* Fully turns off the shadow effect */
	--opacity-placeholder: 0.4;
}

parameters.jsCode:
const raw = $input.first().json.candidates[0].content.parts[0].text;

// Extract JSON block
const jsonMatch = raw.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error("No JSON found in model output");
}

// Parse JSON safely
const parsed = JSON.parse(jsonMatch[0]);

return [{ json: parsed }];

// 1. Keep the current JSON data from your HighLevel node
const currentJson = $input.first().json;

// 2. Teleport the binary image directly from your early node
const originalImage = $('Extract File Content').first().binary.image;

// 3. Staple them together and send them to WhatsApp
return [{
  json: currentJson,
  binary: {
    image: originalImage
  }
}];

